arguments.command:
# Use a small C# project to inspect the API
cd /tmp && mkdir -p inspect && cd inspect && cat > inspect.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <TargetFramework>net10.0</TargetFramework>
    <OutputType>Exe</OutputType>
    <Nullable>enable</Nullable>
    <ImplicitUsings>enable</ImplicitUsings>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="Microsoft.Agents.AI" Version="1.*-*" />
    <PackageReference Include="Microsoft.Extensions.AI.OpenAI" Version="9.*" />
    <PackageReference Include="OpenAI" Version="2.*" />
  </ItemGroup>
</Project>
EOF
cat > Program.cs << 'CEOF'
using System.Reflection;

var asm = typeof(Microsoft.Agents.AI.ChatClientAgent).Assembly;
foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
{
    Console.WriteLine($"=== {t.FullName} ===");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly))
    {
        Console.WriteLine($"  M: {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly))
    {
        Console.WriteLine($"  P: {p.Name} : {p.PropertyType.Name}");
    }
    foreach (var c in t.GetConstructors())
    {
        Console.WriteLine($"  C: ({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
CEOF
