using System.Reflection;

// Check ChatOptions for iteration limits
var t = typeof(Microsoft.Extensions.AI.ChatOptions);
Console.WriteLine($"=== {t.FullName} ===");
foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  P: {p.Name} : {p.PropertyType}");

Console.WriteLine();

// Check AgentResponse
t = typeof(Microsoft.Agents.AI.AgentResponse);
Console.WriteLine($"=== {t.FullName} ===");
foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  P: {p.Name} : {p.PropertyType}");

Console.WriteLine();

// Check AgentResponseUpdate
t = typeof(Microsoft.Agents.AI.AgentResponseUpdate);
Console.WriteLine($"=== {t.FullName} ===");
foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  P: {p.Name} : {p.PropertyType}");

Console.WriteLine();

// Check AgentSession
t = typeof(Microsoft.Agents.AI.AgentSession);
Console.WriteLine($"=== {t.FullName} ===");
foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  P: {p.Name} : {p.PropertyType}");
foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
    Console.WriteLine($"  M: {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");

// Check AIFunction
Console.WriteLine();
t = typeof(Microsoft.Extensions.AI.AIFunction);
Console.WriteLine($"=== {t.FullName} ===");
foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  Static M: {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");

// Check AIFunctionFactory
Console.WriteLine();
foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())
{
    var factory = asm.GetType("Microsoft.Extensions.AI.AIFunctionFactory");
    if (factory != null)
    {
        Console.WriteLine($"=== {factory.FullName} ===");
        foreach (var m in factory.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.DeclaredOnly))
            Console.WriteLine($"  Static M: {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
CEOF
