using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tools ---
var notebook = new ResearchNotebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWebAsync, "search_web",
        "Searches the web for a query and returns a list of result snippets."),

    AIFunctionFactory.Create(FetchUrlAsync, "fetch_url",
        "Fetches the text content from a URL. Use after search_web to read a specific page."),

    AIFunctionFactory.Create(
        ([Description("Short descriptive title for the note")] string title,
         [Description("The research content to save")] string content) =>
        {
            notebook.AddNote(title, content);
            return $"Note saved: \"{title}\" ({content.Length} chars)";
        },
        "save_note",
        "Saves a research note with a title and content for later reference."),

    AIFunctionFactory.Create(
        () => notebook.NoteCount == 0
            ? "No notes saved yet."
            : notebook.GetAllNotes(),
        "get_notes",
        "Retrieves all saved research notes to review before writing a summary."),
};

// --- Agent ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. Given a topic you MUST:

        1. Break the topic into 2-3 key subtopics or questions.
        2. Use search_web to find information on each subtopic.
        3. Optionally use fetch_url to read promising pages in detail.
        4. Use save_note to record key findings after each search (include sources).
        5. Use get_notes to review all gathered research.
        6. Write a comprehensive, well-structured summary with citations.

        Always use your tools — never fabricate information.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking structured notes.",
    tools: tools);

// --- Run ---
var topic = args.Length > 0
    ? string.Join(' ', args)
    : "the latest advances in quantum computing in 2025";

Console.WriteLine($"\u001b[1;36m🔍 Researching:\u001b[0m {topic}");
Console.WriteLine(new string('─', 60));

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine($"\u001b[1;32m📝 {notebook.NoteCount} note(s) saved during research.\u001b[0m");

// --- Tool Implementations ---

async Task<string> SearchWebAsync(
    [Description("The search query")] string query)
{
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_redirect=1&no_html=1";
        var json = await httpClient.GetStringAsync(url);
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var results = new List<string>();

        // Abstract (instant answer)
        var abstractText = root.GetProperty("AbstractText").GetString();
        var abstractSource = root.GetProperty("AbstractSource").GetString();
        var abstractUrl = root.GetProperty("AbstractURL").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            results.Add($"[{abstractSource}] {abstractText}\n  URL: {abstractUrl}");
        }

        // Related topics
        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(5))
            {
                var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                if (!string.IsNullOrWhiteSpace(text))
                {
                    results.Add($"• {text}\n  URL: {firstUrl}");
                }
            }
        }

        return results.Count > 0
            ? $"Search results for \"{query}\":\n\n{string.Join("\n\n", results)}"
            : $"No instant results for \"{query}\". Try fetch_url with a specific URL or refine the query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

async Task<string> FetchUrlAsync(
    [Description("The URL to fetch content from")] string url)
{
    try
    {
        var response = await httpClient.GetAsync(url);
        response.EnsureSuccessStatusCode();
        var html = await response.Content.ReadAsStringAsync();

        // Strip HTML tags for a rough text extraction
        var text = System.Text.RegularExpressions.Regex.Replace(html, "<script[^>]*>[\\s\\S]*?</script>", " ");
        text = System.Text.RegularExpressions.Regex.Replace(text, "<style[^>]*>[\\s\\S]*?</style>", " ");
        text = System.Text.RegularExpressions.Regex.Replace(text, "<[^>]+>", " ");
        text = System.Web.HttpUtility.HtmlDecode(text);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ").Trim();

        // Truncate to avoid overwhelming the context
        const int maxLength = 3000;
        if (text.Length > maxLength)
        {
            text = text[..maxLength] + "... [truncated]";
        }

        return $"Content from {url}:\n\n{text}";
    }
    catch (Exception ex)
    {
        return $"Failed to fetch {url}: {ex.Message}";
    }
}

// --- Notebook ---

sealed class ResearchNotebook
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public int NoteCount => _notes.Count;

    public void AddNote(string title, string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
    }

    public string GetAllNotes()
    {
        var sb = new System.Text.StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var (title, content, ts) = _notes[i];
            sb.AppendLine($"── Note {i + 1}: {title} ({ts:HH:mm:ss UTC}) ──");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

